#!/usr/bin/env python3
"""
gkq_gpu_correctness.py (ADDITIVE)

Loads a real GKQ v1 knot via the UNMODIFIED inference-server-gkq.py loader,
reconstructs every (or N) layer two ways:
   - server NumPy  : MemoryResidentWeightCache._reconstruct_layer   (CPU)
   - GPU kernel    : gkq_gpu_binding.reconstruct_layer_gpu          (sm_61)
and reports the max-abs error. Also runs a tight GPU loop for nvidia-smi proof.
"""
import os, sys, time, importlib.util
import numpy as np

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, HERE)

# import the dash-named server module
spec = importlib.util.spec_from_file_location(
    "inference_server_gkq", os.path.join(HERE, "inference-server-gkq.py"))
srv = importlib.util.module_from_spec(spec)
spec.loader.exec_module(srv)

import gkq_gpu_binding as gpu


def load_cache(knot):
    c = srv.MemoryResidentWeightCache(weights_path=knot, gpu_cache_size_mb=2000)
    c.load_quantized_weights()
    return c


def correctness(knot, n_layers=8):
    c = load_cache(knot)
    layer_keys = [k for k in c.quantized_weights if k.startswith("layer_")]
    layer_ids = sorted(int(k.split("_")[1]) for k in layer_keys)[:n_layers]
    worst = 0.0
    for lid in layer_ids:
        key = f"layer_{lid}"
        q = c.quantized_weights[key]
        m = c.metadata[key]
        W_cpu = c._reconstruct_layer(lid)                  # server NumPy
        W_gpu = gpu.reconstruct_layer_gpu(q, m)            # GPU kernel
        err = float(np.max(np.abs(W_cpu - W_gpu)))
        rel = err / (float(np.max(np.abs(W_cpu))) + 1e-12)
        worst = max(worst, err)
        print(f"  layer_{lid:<3} d_out={m['d_out']:<5} d_in={m['d_in']:<5} "
              f"max|cpu-gpu|={err:.3e}  rel={rel:.2e}")
    print(f"\nWORST max-abs error over {len(layer_ids)} layers: {worst:.3e}")
    assert worst < 1e-3, f"correctness FAILED: {worst} >= 1e-3"
    print("CORRECTNESS PASS (< 1e-3)")
    return c, layer_ids


def gpu_loop(c, layer_ids, seconds=25):
    """Tight GPU reconstruction loop so nvidia-smi can sample utilization."""
    keys = [f"layer_{l}" for l in layer_ids]
    qs = [(c.quantized_weights[k], c.metadata[k]) for k in keys]
    gpu.get_reconstructor()  # warm compile
    print(f"[gpu_loop] running ~{seconds}s of GPU reconstructions...")
    t0 = time.time(); n = 0
    while time.time() - t0 < seconds:
        for q, m in qs:
            gpu.reconstruct_layer_gpu(q, m); n += 1
    print(f"[gpu_loop] done: {n} GPU reconstructions in {time.time()-t0:.1f}s")


if __name__ == "__main__":
    knot = os.getenv("WEIGHTS_PATH",
                     os.path.join(HERE, "rknots", "llama-gkq.knot"))
    mode = sys.argv[1] if len(sys.argv) > 1 else "correctness"
    print(f"knot = {knot}")
    c, layer_ids = correctness(knot)
    if mode == "loop":
        secs = int(sys.argv[2]) if len(sys.argv) > 2 else 25
        gpu_loop(c, layer_ids, secs)
